	maxObjects := effectiveMaxObjects(e.params.MaxObjects)
	if len(hashes) <= maxObjects {
		return nil
	}
	return fmt.Errorf(
		"materialized push requires %d objects (limit %d); use bootstrap for large initial syncs",
		len(hashes), maxObjects,
	)
}

